// Payload: { action: 'update_status', id, status, requested_by, timestamp }
const body = $input.first().json.body || {};
if (body.action !== 'update_status') {
  return [{ json: { ok: false, error: 'Unknown action' } }];
}
if (!body.id || !body.status) {
  return [{ json: { ok: false, error: 'Missing id or status' } }];
}
// Allowed statuses: идэвхтэй, гарсан, нээлттэй, чөлөөтэй
const allowed = ['идэвхтэй', 'гарсан', 'нээлттэй', 'чөлөөтэй'];
if (!allowed.includes(body.status)) {
  return [{ json: { ok: false, error: 'Invalid status' } }];
}
// Google Sheets node-нд шилжихэд тохирох format
return [{
  json: {
    'ID': String(body.id),
    'Төлөв': body.status,
    requested_by: body.requested_by || 'unknown',
    timestamp: body.timestamp || new Date().toISOString(),
  },
}];
